// minimise or maxmise the chat window
function MaxMinimise() {

    if (botDiv.classList.contains("botDivMin")) {

        botDiv.classList.remove("botDivMin");
        localStorage.removeItem("maxMinimise");
    }
    else {
        botDiv.classList.add("botDivMin");
        localStorage.setItem("maxMinimise", 1);
    }
}


