/* 
*   Namespace:      Bot.Web
*   Class:          Max
*   Description:    Use this class to initiate Max and for all JS manipulation
*                   This class is also used for capturiing and logging user tracking
*          
*/

class Max {

    constructor(useragent = "Not Provided", titlebar = "How can I help you?", username = "Me") {

        this._pageurl = document.referrer;
        this.parenturl;
        this.client = null;
        this._conversationid = null;
        this._timestamp = null;
        this._ip = "0.0.0.0"; //this.getClientIP();
        this._useragent = useragent;
        this._titlebar = titlebar;
        this._username = username;
        this._maxmin = 1;
        this._activities = [];
        this._inCognito = false;

        try
        {
            if (localStorage.getItem("maxSessionId") != null) {
                this._sessionId = localStorage.getItem("maxSessionId");
            }
            else
            {
                this._sessionId = this.createSessionId();
                localStorage.setItem("maxSessionId", this._sessionId);
            }
        }
        catch (e)
        {
            this._sessionId = this.createSessionId();
            this._inCognito = true;
        }
    }

    async start() {
        if (this._inCognito == false) {
            this.setTimestamp(localStorage.getItem("timestamp"));
            this.checkExpiration();
        }

        //let url = 'https://parkingmax.co.uk/Home/GetSettings';
        let url = 'https://maxchatbot.co.uk/Home/GetSettings';
        //let url = 'https://demomaxweb.azurewebsites.net/Home/GetSettings';
        //let url = 'https://kishmaxweb.azurewebsites.net/Home/GetSettings';


        this.parenturl = atob(this.getUrlParameter('p'));
        let host = atob(this.getUrlParameter('h'));


        var payload = {
            pageUrl: this._pageurl,
            host: host
        };

        let request = new Request(url, {
            method: 'post',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload)
        });

        const response = await fetch(request);
        this.client = await response.json();

        this.createMax(this.client);
    }

    async createMax() {

        let language;

        if (this._inCognito == false) {
            var convoId = localStorage.getItem("convoId");
        }

        if (sessionStorage.getItem("language") != null) {
            language = sessionStorage.getItem("language");
        }
        else {
            language = 'en';
        }

        console.log('Language in Max: ' + language);

        if (this.getUrlParameter('pcn') != null) {
            var initData = {
                client: this.client.clientId,
                url: this._pageurl,
                pcn: this.getUrlParameter('pcn'),
                contra: this.getUrlParameter('contra'),
                driverProcessId: this.getUrlParameter('driverProcessId'),
                language: language
            }
        } else {
            var initData = {
                client: this.client.clientId,
                url: this._pageurl,
                language: language
            }
